import sys

def solve():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = list(map(int, data[1:N+1]))

    if all(x == 1 for x in A):
        print("Yes")
        return

    from collections import deque

    q = deque()
    for i in range(N):
        if A[i] == 0:
            q.append(i)

    while q:
        pos = q.popleft()
        # Check first operation: S_i = A, S_{i+1} = R, S_{i+2} = C
        if pos + 2 < N:
            if A[pos] == 0 and A[pos+1] == 1 and A[pos+2] == 1:
                A[pos] = 1
                if A[pos] == 0:
                    q.append(pos)
        # Check second operation: S_{i+2} = A, S_{i+1} = R, S_i = C
        if pos - 2 >= 0:
            if A[pos-2] == 1 and A[pos-1] == 1 and A[pos] == 0:
                A[pos] = 1
                if A[pos] == 0:
                    q.append(pos)
        # Also check the wrap-around cases
        if pos + 2 == N:
            if A[pos] == 0 and A[pos+1] == 1 and A[pos+2] == A[0]:
                A[pos] = 1
                if A[pos] == 0:
                    q.append(pos)
        if pos - 2 < 0:
            if A[pos-2 + N] == 1 and A[pos-1 + N] == 1 and A[pos] == 0:
                A[pos] = 1
                if A[pos] == 0:
                    q.append(pos)

    if all(x == 1 for x in A):
        print("Yes")
    else:
        print("No")

solve()
